mapper.sql:
usp.deleted = 0
AND usp.store_id = #{storeId}

    AND (
        CAST(usp.user_id AS CHAR) = #{keyword}
        OR u.nickname LIKE CONCAT('%', #{keyword}, '%')
        OR u.phone LIKE CONCAT('%', #{keyword}, '%')
    )

deleted = 0
AND store_id = #{storeId}
AND user_id = #{userId}
AND status = #{status}

mapper.select:
SELECT spr.*, u.nickname, u.phone, u.status AS user_status
FROM store_points_request spr
LEFT JOIN `user` u ON u.id = spr.user_id AND u.deleted = 0
WHERE spr.deleted = 0
AND spr.store_id = #{storeId}
AND spr.user_id = #{userId}
AND spr.status = #{status}
ORDER BY spr.id DESC LIMIT #{offset}, #{size}
